mapper.select:
SELECT IFNULL(sum(amount), 0)
FROM transaction_record
WHERE user_id = #{userId}
AND type = #{type}
AND YEAR(record_date) = #{year}
AND MONTH(record_date) = #{month}

SELECT transaction_category.name AS categoryName, IFNULL(SUM(transaction_record.amount), 0) AS totalAmount
FROM transaction_record
INNER JOIN transaction_category
ON transaction_record.category_id = transaction_category.id
WHERE transaction_record.user_id = #{userId}
AND transaction_category.user_id = #{userId}
AND transaction_record.type = #{type}
AND YEAR(transaction_record.record_date) = #{year}
AND MONTH(transaction_record.record_date) = #{month}
GROUP BY transaction_category.id,  transaction_category.name
